  const auto find_popup = []() -> QWidget* {
    QWidget* popup = nullptr;
    for (auto* widget : QApplication::topLevelWidgets()) {
      if (widget->objectName() == QStringLiteral("brushTipPickerPopup") && widget->isVisible()) {
        popup = widget;
      }
    }
    return popup;
  };

  picker->click();
