void ui_style_preset_pattern_apply_cancel_restores_document_store() {
  QTemporaryDir directory;
  CHECK(directory.isValid());
  patchy::ui::StyleLibrary library(directory.filePath(QStringLiteral("library")));
  // A preset whose pattern id will collide with different document pixels.
  const auto pattern_id = std::string("99999999-1111-2222-3333-444444444444");
  patchy::PatternResource preset_tile;
  preset_tile.id = pattern_id;
  preset_tile.name = "Preset Tile";
  preset_tile.tile = solid_pixels(4, 4, patchy::PixelFormat::rgba8(), QColor(40, 200, 90, 255));
  preset_tile.provenance = patchy::PatternProvenance::Authored;
  patchy::LayerStyle style;
  patchy::LayerPatternOverlay overlay;
  overlay.enabled = true;
  overlay.pattern_id = pattern_id;
  overlay.pattern_name = "Preset Tile";
  style.pattern_overlays.push_back(overlay);
  const auto storage_id =
      library.add_style(QStringLiteral("Pattern Preset"), style, std::nullopt,
                        std::span<const patchy::PatternResource>(&preset_tile, 1));
  CHECK(!storage_id.isEmpty());

  patchy::Document document(96, 72, patchy::PixelFormat::rgba8());
  patchy::PatternResource embedded;
  embedded.id = pattern_id;
  embedded.name = "Embedded Collision";
  embedded.tile = solid_pixels(3, 3, patchy::PixelFormat::rgba8(), QColor(180, 20, 30, 255));
  embedded.provenance = patchy::PatternProvenance::ImportedRaw;
  document.metadata().patterns.adopt(embedded);
  patchy::Layer layer(document.allocate_layer_id(), "Styled",
                      solid_pixels(48, 36, patchy::PixelFormat::rgba8(), QColor(80, 140, 220, 255)));

  std::string applied_alias;
  QTimer::singleShot(0, [&] {
    auto* dialog =
        qobject_cast<QDialog*>(find_top_level_dialog(QStringLiteral("patchyLayerStyleDialog")));
    CHECK(dialog != nullptr);
    auto* categories = dialog->findChild<QListWidget*>(QStringLiteral("layerStyleCategoryList"));
    auto* browser =
        dialog->findChild<patchy::ui::StyleBrowserWidget*>(QStringLiteral("layerStyleStylesBrowser"));
    CHECK(categories != nullptr && browser != nullptr);
    const auto styles_items = categories->findItems(QStringLiteral("Style Presets"), Qt::MatchExactly);
    CHECK(!styles_items.empty());
    categories->setCurrentItem(styles_items.front());
    QApplication::processEvents();
    click_style_tree_item(*browser, style_tree_item_for_storage_id(*browser, storage_id));
    QApplication::processEvents();
    // The collision produced a document-local alias with the preset pixels.
    CHECK(document.metadata().patterns.patterns.size() == 2U);
    for (const auto& resource : document.metadata().patterns.patterns) {
      if (resource.id != pattern_id) {
        applied_alias = resource.id;
        CHECK(resource.tile.pixel(0, 0)[1] == 200);
      }
    }
    CHECK(!applied_alias.empty());
    QTimer::singleShot(50, dialog, [dialog] { dialog->reject(); });
  });

  const auto settings = patchy::ui::request_layer_style_settings(
      nullptr, layer, {}, &document.metadata().patterns, nullptr, &library);
  CHECK(!settings.has_value());
  // MainWindow restores the snapshot on cancel; here the dialog must not have
  // touched the original embedded resource and the alias must reference the
  // preset pixels it adopted.
  CHECK(document.metadata().patterns.find(pattern_id) != nullptr);
  CHECK(document.metadata().patterns.find(pattern_id)->tile.pixel(0, 0)[0] == 180);
  CHECK(!applied_alias.empty());
  CHECK(document.metadata().patterns.find(applied_alias) != nullptr);
}

void ui_default_brush_tips_seed_once_and_render_sheet() {
  clear_brush_tip_test_state();
  {
    auto settings = patchy::ui::app_settings();
    settings.setValue(QStringLiteral("brushes/defaultTipsVersion"), 0);
    settings.sync();
  }

  patchy::ui::MainWindow window;
  show_window(window);
  auto& library = window.brush_tip_library();
  const auto specs = patchy::ui::generate_default_brush_tips();
  CHECK(specs.size() == 36);
  CHECK(library.entries().size() == specs.size());
  const auto folder = patchy::ui::default_brush_tips_folder_name();
  for (const auto& entry : library.entries()) {
    CHECK(entry.folder == folder);
    CHECK(entry.size.width() > 0 && entry.size.width() <= 200);
    CHECK(entry.size.height() > 0 && entry.size.height() <= 200);
  }
  CHECK(library.folders() == QStringList{folder});

  // Thumbnails ride on a light paper chip so they stay visible on the dark toolbar/popup;
  // save a strip on the UI background color for visual review.
  {
    constexpr int kThumb = 48;
    constexpr int kPad = 8;
    const auto count = static_cast<int>(library.entries().size());
    QImage strip((kThumb + kPad) * count + kPad, kThumb + 2 * kPad, QImage::Format_RGB32);
    strip.fill(QColor(0x2B, 0x2B, 0x2B));
    QPainter strip_painter(&strip);
    int strip_x = kPad;
    int visible_thumbnails = 0;
    for (const auto& entry : library.entries()) {
      strip_painter.drawPixmap(strip_x, kPad, entry.thumbnail);
      const auto image = entry.thumbnail.toImage();
      int bright_pixels = 0;
      for (int y = 0; y < image.height(); ++y) {
        for (int x = 0; x < image.width(); ++x) {
          if (qAlpha(image.pixel(x, y)) > 200 && qGray(image.pixel(x, y)) > 150) {
            ++bright_pixels;
          }
        }
      }
      // Every thumbnail must carry a light backing (not just black-on-transparent ink).
      if (bright_pixels > kThumb * kThumb / 10) {
        ++visible_thumbnails;
      }
      strip_x += kThumb + kPad;
    }
    strip_painter.end();
    CHECK(visible_thumbnails == count);
    ensure_artifact_dir();
    CHECK(strip.save(QStringLiteral("test-artifacts/ui_brush_tip_thumbnails_dark.png")));
  }

  // Deleting a seeded tip must stick: the version gate stops re-seeding. "Restore Defaults"
  // is the explicit way back.
  const auto first_id = library.entries().front().id;
  CHECK(library.remove_tip(first_id));
  {
    patchy::ui::MainWindow second_window;
    show_window(second_window);
    auto& second_library = second_window.brush_tip_library();
    CHECK(second_library.entries().size() == specs.size() - 1);
    CHECK(second_library.restore_default_tips() == 1);
    CHECK(second_library.entries().size() == specs.size());
    CHECK(second_library.restore_default_tips() == 0);  // idempotent when nothing is missing
  }

  // Contact sheet: a real engine stroke plus a single stamp per tip, for visual review.
  constexpr int kCellWidth = 340;
  constexpr int kCellHeight = 96;
  constexpr int kColumns = 2;
  const int rows = (static_cast<int>(specs.size()) + kColumns - 1) / kColumns;
  QImage sheet(kColumns * kCellWidth, rows * kCellHeight, QImage::Format_RGB32);
  sheet.fill(Qt::white);
  QPainter painter(&sheet);
  int cell_index = 0;
  for (const auto& spec : specs) {
    const auto cell_x = (cell_index % kColumns) * kCellWidth;
    const auto cell_y = (cell_index / kColumns) * kCellHeight;
    ++cell_index;

    patchy::Document document(kCellWidth, kCellHeight, patchy::PixelFormat::rgba8());
    patchy::PixelBuffer pixels(kCellWidth, kCellHeight, patchy::PixelFormat::rgba8());
    pixels.clear(0);
    const auto layer_id = document.add_pixel_layer("Stroke", std::move(pixels)).id();
    const auto mips = patchy::build_brush_tip_mips(spec.tip);
    const auto brush_size = 44;
    const auto scaled = patchy::make_scaled_brush_tip(mips, brush_size);
    CHECK(!scaled.empty());
    patchy::EditOptions options;
    options.primary = patchy::EditColor{0, 0, 0, 255};
    options.brush_size = brush_size;
    options.brush_tip = &scaled;
    options.brush_tip_spacing = spec.spacing;
    // Matches the app's stroke behavior at full opacity: overlapping dabs accumulate toward
    // solid coverage (CanvasWidget's stroke compositor), so no per-pixel gate is needed here —
    // plain source-over dab compositing produces the same result.
    patchy::BrushTipStrokeState state;
    double previous_x = 120.0;
    double previous_y = kCellHeight / 2.0;
    for (int step = 1; step <= 32; ++step) {
      const auto t = static_cast<double>(step) / 32.0;
      const auto x = 120.0 + t * (kCellWidth - 180.0);
      const auto y = kCellHeight / 2.0 - std::sin(t * 2.0 * 3.14159265358979323846) * (kCellHeight / 2.0 - 26.0);
      (void)patchy::paint_brush_segment(document, layer_id, previous_x, previous_y, x, y, options, false, state);
      previous_x = x;
      previous_y = y;
    }
    const auto* layer = document.find_layer(layer_id);
    CHECK(layer != nullptr);
    int painted = 0;
    QImage stroke(kCellWidth, kCellHeight, QImage::Format_RGBA8888);
    for (int y = 0; y < kCellHeight; ++y) {
      const auto row = layer->pixels().row(y);
      std::memcpy(stroke.scanLine(y), row.data(), static_cast<std::size_t>(kCellWidth) * 4U);
      for (int x = 0; x < kCellWidth; ++x) {
        painted += row.data()[static_cast<std::size_t>(x) * 4U + 3U] > 0U ? 1 : 0;
      }
    }
    CHECK(painted > 200);  // every default tip must lay down real coverage
    painter.drawImage(cell_x, cell_y, stroke);
    painter.setPen(Qt::black);
    painter.drawText(QRect(cell_x + 6, cell_y + 4, 110, 40), Qt::AlignLeft | Qt::AlignTop | Qt::TextWordWrap,
                     QStringLiteral("%1\n%2%").arg(spec.name).arg(std::lround(spec.spacing * 100.0)));
    painter.setPen(QColor(0, 0, 0, 30));
    painter.drawRect(cell_x, cell_y, kCellWidth - 1, kCellHeight - 1);
  }
  painter.end();
  ensure_artifact_dir();
  CHECK(sheet.save(QStringLiteral("test-artifacts/ui_default_brush_tips_sheet.png")));

  // since_version filtering: a v2 install only gains the v3 additions on upgrade; the
  // parameterless overload (the manager's Restore button) still restores everything missing.
  {
    patchy::ui::BrushTipLibrary versioned(brush_tip_test_storage_dir() + QStringLiteral("/v2-upgrade"));
    CHECK(versioned.restore_default_tips(2) == 20);  // only the v3 tips seed
    CHECK(versioned.restore_default_tips(2) == 0);   // idempotent
    CHECK(versioned.restore_default_tips() == 16);   // explicit restore brings back the originals
    CHECK(versioned.entries().size() == specs.size());
  }

  // Upgrade end-to-end: simulate a v2 install that deleted an original default ("Chalk") and
  // never had a v3 tip ("Snowflake"). The version-gated seeding must re-add only the new tip
  // and leave the deletion alone, then advance the stored version.
  {
    patchy::ui::BrushTipLibrary storage(brush_tip_test_storage_dir());
    const auto entry_id = [&storage, &folder](const QString& name) {
      for (const auto& entry : storage.entries()) {
        if (entry.folder == folder && entry.name == name) {
          return entry.id;
        }
      }
      return QString();
    };
    CHECK(storage.remove_tip(entry_id(QStringLiteral("Chalk"))));
    CHECK(storage.remove_tip(entry_id(QStringLiteral("Snowflake"))));
  }
  {
    auto settings = patchy::ui::app_settings();
    settings.setValue(QStringLiteral("brushes/defaultTipsVersion"), 2);
    settings.sync();
  }
  {
    patchy::ui::MainWindow upgraded_window;
    show_window(upgraded_window);
    auto& upgraded = upgraded_window.brush_tip_library();
    bool has_chalk = false;
    bool has_snowflake = false;
    for (const auto& entry : upgraded.entries()) {
      has_chalk = has_chalk || (entry.folder == folder && entry.name == QStringLiteral("Chalk"));
      has_snowflake =
          has_snowflake || (entry.folder == folder && entry.name == QStringLiteral("Snowflake"));
    }
    CHECK(!has_chalk);      // the deliberate deletion is respected across the upgrade
    CHECK(has_snowflake);   // the tip introduced after v2 is seeded
    CHECK(upgraded.entries().size() == specs.size() - 1);
    CHECK(patchy::ui::app_settings().value(QStringLiteral("brushes/defaultTipsVersion")).toInt() == 3);
  }

  // A stale MASK (a tip seeded before a generator artwork fix) also heals via the factory
  // reset: the PNG is rewritten in place under the same id.
  QString stale_star_id;
  {
    patchy::ui::BrushTipLibrary storage(brush_tip_test_storage_dir());
    for (const auto& entry : storage.entries()) {
      if (entry.folder == folder && entry.name == QStringLiteral("Star")) {
        stale_star_id = entry.id;
      }
    }
    CHECK(!stale_star_id.isEmpty());
    QImage stale(8, 8, QImage::Format_Grayscale8);
    stale.fill(255);
    CHECK(stale.save(
        brush_tip_test_storage_dir() + QStringLiteral("/") + stale_star_id + QStringLiteral(".png"),
        "PNG"));
  }
  {
    patchy::ui::BrushTipLibrary storage(brush_tip_test_storage_dir());
    const auto* stale_star = storage.find_entry(stale_star_id);
    CHECK(stale_star != nullptr);
    CHECK(stale_star->size == QSize(8, 8));
    CHECK(storage.reset_default_tips_to_factory() == 1);  // only the doctored Star differs
    const auto* fixed = storage.find_entry(stale_star_id);
    CHECK(fixed != nullptr);
    CHECK(fixed->size.width() > 100 && fixed->size.height() > 100);
    const auto reloaded_tip = storage.tip(stale_star_id);
    CHECK(reloaded_tip != nullptr);
    CHECK(reloaded_tip->width == fixed->size.width());
    CHECK(storage.reset_default_tips_to_factory() == 0);  // idempotent once factory
  }
  clear_brush_tip_test_state();
}

void ui_brush_tip_folders_and_bulk_delete() {
  clear_brush_tip_test_state();
  patchy::ui::MainWindow window;
  show_window(window);
  auto& library = window.brush_tip_library();

  // Imported sets land in a folder named after the file.
  QString error;
  QStringList warnings;
  const auto fixture =
      QString::fromStdString(patchy::test::committed_abr_fixture_path("myer-settlement-brushes.abr").string());
  const auto first_id = library.import_abr(fixture, error, warnings);
  CHECK(!first_id.isEmpty());
  CHECK(library.entries().size() == 148);
  CHECK(library.folders() == QStringList{QStringLiteral("myer-settlement-brushes")});
  CHECK(library.find_entry(first_id)->folder == QStringLiteral("myer-settlement-brushes"));

  const auto loose_id = library.add_tip(QStringLiteral("Loose"), make_bar_tip_image(), 0.25);
  CHECK(!loose_id.isEmpty());
  CHECK(library.find_entry(loose_id)->folder.isEmpty());
  // Ungrouped tips sort ahead of foldered ones.
  CHECK(library.entries().front().id == loose_id);

  // Moving between folders rewrites the sidecar and regroups.
  CHECK(library.set_tip_folder(loose_id, QStringLiteral("My Set")));
  CHECK(library.find_entry(loose_id)->folder == QStringLiteral("My Set"));
  CHECK(library.folders().contains(QStringLiteral("My Set")));

  // Bulk delete removes everything in one changed() notification.
  int changed_signals = 0;
  QObject::connect(&library, &patchy::ui::BrushTipLibrary::changed, &window, [&changed_signals] {
    ++changed_signals;
  });
  QStringList doomed;
  for (const auto& entry : library.entries()) {
    if (entry.folder == QStringLiteral("myer-settlement-brushes")) {
      doomed.append(entry.id);
    }
  }
  CHECK(doomed.size() == 148);
  CHECK(library.remove_tips(doomed) == 148);
  CHECK(changed_signals == 1);
  CHECK(library.entries().size() == 1);
  CHECK(library.folders() == QStringList{QStringLiteral("My Set")});

  // The removal is durable: a fresh library sees the same state.
  patchy::ui::BrushTipLibrary reloaded(brush_tip_test_storage_dir());
  CHECK(reloaded.entries().size() == 1);
  CHECK(reloaded.find_entry(loose_id) != nullptr);
  clear_brush_tip_test_state();
}

void ui_brush_tip_resets_to_round_on_startup() {
  clear_brush_tip_test_state();
  QString tip_id;
  {
    patchy::ui::MainWindow window;
    show_window(window);
    auto& library = window.brush_tip_library();
    tip_id = library.add_tip(QStringLiteral("Session Bar"), make_bar_tip_image(), 0.5);
    CHECK(!tip_id.isEmpty());
    window.set_active_brush_tip(tip_id, false);
    CHECK(require_canvas(window)->has_brush_tip());
    process_events_for(400);  // any debounced tool-settings save must not record the tip
    CHECK(!patchy::ui::app_settings().contains(QStringLiteral("tools/brushTip")));
  }
  {
    // A fresh launch always starts with the procedural Round tip at 100% opacity /
    // 0% soft, even though a bitmap tip was active when the last window closed.
    patchy::ui::MainWindow window;
    show_window(window);
    auto* canvas = require_canvas(window);
    CHECK(!canvas->has_brush_tip());
    CHECK(canvas->brush_opacity() == 100);
    CHECK(canvas->brush_softness() == 0);
    auto* picker = window.findChild<patchy::ui::BrushTipPicker*>(QStringLiteral("brushTipPicker"));
    CHECK(picker != nullptr);
    CHECK(picker->current_tip_id() == patchy::ui::builtin_round_brush_tip_id());
  }
  clear_brush_tip_test_state();
}

void ui_tab_switch_layers_follow_the_canvas_after_tab_reorder() {
  patchy::ui::MainWindow window;
  show_window(window);
  auto* tabs = qobject_cast<QTabWidget*>(window.centralWidget());
  auto* layer_list = window.findChild<QListWidget*>(QStringLiteral("layerList"));
  CHECK(tabs != nullptr);
  CHECK(layer_list != nullptr);

  require_action(window, "layerNewAction")->trigger();
  QApplication::processEvents();
  auto* first_canvas = tabs->currentWidget();
  CHECK(!top_level_widget_exists(QStringLiteral("patchyNewLayerDialog")));
  CHECK(layer_list->count() == 3);
  CHECK(require_layer_item(*layer_list, QStringLiteral("Layer 3")) != nullptr);

  accept_new_document_dialog(360, 240);
  require_action_by_text(window, QStringLiteral("New"))->trigger();
  QApplication::processEvents();
  auto* second_canvas = tabs->currentWidget();
  CHECK(layer_list->count() == 2);

  auto* tab_bar = tabs->findChild<QTabBar*>();
  CHECK(tab_bar != nullptr);
  tab_bar->moveTab(tabs->indexOf(first_canvas), tabs->count() - 1);
  QApplication::processEvents();

  tabs->setCurrentWidget(first_canvas);
  QApplication::processEvents();
  CHECK(layer_list->count() == 3);
  CHECK(require_layer_item(*layer_list, QStringLiteral("Layer 3")) != nullptr);

  tabs->setCurrentWidget(second_canvas);
  QApplication::processEvents();
  CHECK(layer_list->count() == 2);
  save_widget_artifact("ui_tab_session_layers", window);
}

void ui_new_layer_defaults_and_multiselect_layers_work() {
  patchy::ui::MainWindow window;
  show_window(window);
  auto* layer_list = window.findChild<QListWidget*>(QStringLiteral("layerList"));
  CHECK(layer_list != nullptr);
  CHECK(layer_list->selectionMode() == QAbstractItemView::ExtendedSelection);

  require_action(window, "layerNewAction")->trigger();
  QApplication::processEvents();
  CHECK(!top_level_widget_exists(QStringLiteral("patchyNewLayerDialog")));
  CHECK(layer_list->count() == 3);
  CHECK(layer_list->item(0)->text() == QStringLiteral("Layer 3"));
  save_widget_artifact("ui_new_layer_result", window);

  require_action(window, "layerNewAction")->trigger();
  QApplication::processEvents();
  CHECK(layer_list->count() == 4);
  CHECK(layer_list->item(0)->text() == QStringLiteral("Layer 4"));

  layer_list->clearSelection();
  layer_list->item(0)->setSelected(true);
  layer_list->item(1)->setSelected(true);
  CHECK(layer_list->selectedItems().size() == 2);
  require_action(window, "layerMergeDownAction")->trigger();
  QApplication::processEvents();
  CHECK(layer_list->count() == 3);
  CHECK(layer_list->item(0)->text() == QStringLiteral("Layer 3"));
  save_widget_artifact("ui_multiselect_merge_down", window);

  layer_list->clearSelection();
  layer_list->item(0)->setSelected(true);
  layer_list->item(1)->setSelected(true);
  require_action(window, "layerDuplicateAction")->trigger();
  QApplication::processEvents();
  CHECK(layer_list->count() == 5);

  layer_list->clearSelection();
  layer_list->item(0)->setSelected(true);
  layer_list->item(1)->setSelected(true);
  require_action(window, "layerDeleteAction")->trigger();
  QApplication::processEvents();
  CHECK(layer_list->count() == 3);
  save_widget_artifact("ui_multiselect_duplicate_delete", window);
}

void ui_merge_down_repeatedly_collapses_to_one_layer() {
  patchy::Document document(48, 36, patchy::PixelFormat::rgba8());
  auto bottom_pixels = solid_pixels(48, 36, patchy::PixelFormat::rgba8(), QColor(0, 0, 0, 0));
  fill_pixel_rect(bottom_pixels, QRect(4, 4, 12, 12), QColor(40, 90, 220, 255));
  document.add_layer(patchy::Layer(document.allocate_layer_id(), "Bottom", std::move(bottom_pixels)));

  auto middle_pixels = solid_pixels(48, 36, patchy::PixelFormat::rgba8(), QColor(0, 0, 0, 0));
  fill_pixel_rect(middle_pixels, QRect(16, 8, 12, 12), QColor(40, 180, 80, 192));
  document.add_layer(patchy::Layer(document.allocate_layer_id(), "Middle", std::move(middle_pixels)));

  auto top_pixels = solid_pixels(48, 36, patchy::PixelFormat::rgba8(), QColor(0, 0, 0, 0));
  fill_pixel_rect(top_pixels, QRect(28, 12, 12, 12), QColor(230, 50, 50, 160));
  document.add_layer(patchy::Layer(document.allocate_layer_id(), "Top", std::move(top_pixels)));

  patchy::ui::MainWindow window;
  window.add_document_session(std::move(document), QStringLiteral("Merge Down Repeated"));
  show_window(window);
  auto* layer_list = window.findChild<QListWidget*>(QStringLiteral("layerList"));
  CHECK(layer_list != nullptr);
  CHECK(layer_list->count() == 3);

  require_action(window, "layerMergeDownAction")->trigger();
  QApplication::processEvents();
  CHECK(layer_list->count() == 2);
  CHECK(layer_list->item(0)->text() == QStringLiteral("Middle"));

  require_action(window, "layerMergeDownAction")->trigger();
  QApplication::processEvents();
  CHECK(layer_list->count() == 1);
  CHECK(layer_list->item(0)->text() == QStringLiteral("Bottom"));
}

void ui_merge_down_preserves_transparent_pixels() {
  patchy::Document document(32, 24, patchy::PixelFormat::rgba8());
  auto lower_pixels = solid_pixels(32, 24, patchy::PixelFormat::rgba8(), QColor(0, 0, 0, 0));
  fill_pixel_rect(lower_pixels, QRect(6, 6, 8, 8), QColor(40, 90, 220, 128));
  document.add_layer(patchy::Layer(document.allocate_layer_id(), "Lower", std::move(lower_pixels)));

  auto upper_pixels = solid_pixels(32, 24, patchy::PixelFormat::rgba8(), QColor(0, 0, 0, 0));
  fill_pixel_rect(upper_pixels, QRect(12, 8, 8, 8), QColor(230, 40, 40, 128));
  document.add_layer(patchy::Layer(document.allocate_layer_id(), "Upper", std::move(upper_pixels)));

  patchy::ui::MainWindow window;
  window.add_document_session(std::move(document), QStringLiteral("Merge Down Alpha"));
  show_window(window);
  auto* layer_list = window.findChild<QListWidget*>(QStringLiteral("layerList"));
  CHECK(layer_list != nullptr);

  require_action(window, "layerMergeDownAction")->trigger();
  QApplication::processEvents();
  CHECK(layer_list->count() == 1);

  QApplication::clipboard()->clear();
  require_action(window, "editSelectAllAction")->trigger();
  QApplication::processEvents();
  require_action(window, "editCopyAction")->trigger();
  QApplication::processEvents();
  const auto copied = QApplication::clipboard()->image().convertToFormat(QImage::Format_RGBA8888);
  CHECK(!copied.isNull());
  CHECK(copied.pixelColor(0, 0).alpha() == 0);
  CHECK(copied.pixelColor(8, 8).alpha() > 0);
  CHECK(copied.pixelColor(14, 10).alpha() > 0);
}

void ui_merge_down_rasterizes_text_target() {
  patchy::Document document(160, 96, patchy::PixelFormat::rgba8());
  patchy::Layer text_layer(document.allocate_layer_id(), "Text: Lower", patchy::LayerKind::Text);
  text_layer.set_bounds(patchy::Rect{18, 22, 120, 42});
  text_layer.metadata()[patchy::kLayerMetadataText] = "Lower";
  text_layer.metadata()[patchy::kLayerMetadataTextSize] = "30";
  text_layer.metadata()[patchy::kLayerMetadataTextColor] = "#2040ff";
  document.add_layer(std::move(text_layer));

  auto paint_pixels = solid_pixels(160, 96, patchy::PixelFormat::rgba8(), QColor(0, 0, 0, 0));
  fill_pixel_rect(paint_pixels, QRect(52, 44, 40, 18), QColor(230, 40, 40, 160));
  document.add_layer(patchy::Layer(document.allocate_layer_id(), "Paint", std::move(paint_pixels)));

  patchy::ui::MainWindow window;
  window.add_document_session(std::move(document), QStringLiteral("Merge Down Text"));
  show_window(window);
  auto* layer_list = window.findChild<QListWidget*>(QStringLiteral("layerList"));
  CHECK(layer_list != nullptr);

  require_action(window, "layerMergeDownAction")->trigger();
  QApplication::processEvents();
  CHECK(layer_list->count() == 1);
  CHECK(layer_list->item(0)->text() == QStringLiteral("Text: Lower"));

  auto* row = layer_list->itemWidget(layer_list->item(0));
  CHECK(row != nullptr);
  auto* thumbnail = row->findChild<QLabel*>(QStringLiteral("layerContentThumbnail"));
  CHECK(thumbnail != nullptr);
  CHECK(thumbnail->toolTip() == QStringLiteral("Layer thumbnail"));

  auto* layer_info = window.findChild<QLabel*>(QStringLiteral("activeLayerInfoLabel"));
  auto* text_info = window.findChild<QLabel*>(QStringLiteral("activeLayerTextLabel"));
  CHECK(layer_info != nullptr);
  CHECK(text_info != nullptr);
  CHECK(layer_info->text().contains(QStringLiteral("Pixel Layer")));
  CHECK(text_info->isHidden() || text_info->text().isEmpty());
}

void ui_merge_down_flattens_single_folder_in_place() {
  patchy::Document document(48, 36, patchy::PixelFormat::rgba8());

  auto base_pixels = solid_pixels(48, 36, patchy::PixelFormat::rgba8(), Qt::transparent);
  fill_pixel_rect(base_pixels, QRect(2, 2, 10, 10), QColor(210, 40, 40, 255));
  document.add_layer(patchy::Layer(document.allocate_layer_id(), "Base", std::move(base_pixels)));

  patchy::Layer folder(document.allocate_layer_id(), "Folder", patchy::LayerKind::Group);
  auto child_one = solid_pixels(48, 36, patchy::PixelFormat::rgba8(), Qt::transparent);
  fill_pixel_rect(child_one, QRect(20, 4, 10, 10), QColor(40, 200, 40, 255));
  folder.add_child(patchy::Layer(document.allocate_layer_id(), "Folder Paint A", std::move(child_one)));
  auto child_two = solid_pixels(48, 36, patchy::PixelFormat::rgba8(), Qt::transparent);
  fill_pixel_rect(child_two, QRect(34, 20, 10, 10), QColor(40, 40, 200, 255));
  folder.add_child(patchy::Layer(document.allocate_layer_id(), "Folder Paint B", std::move(child_two)));
  document.add_layer(std::move(folder));

  patchy::ui::MainWindow window;
  window.add_document_session(std::move(document), QStringLiteral("Flatten Folder"));
  show_window(window);
  auto* layer_list = window.findChild<QListWidget*>(QStringLiteral("layerList"));
  CHECK(layer_list != nullptr);

  auto* folder_item = require_layer_item(*layer_list, QStringLiteral("Folder"));
  layer_list->clearSelection();
  layer_list->setCurrentItem(folder_item);
  folder_item->setSelected(true);
  require_action(window, "layerMergeDownAction")->trigger();
  QApplication::processEvents();

  // A single folder flattens in place (Photoshop "Merge Group"); the layer below is untouched.
  CHECK(layer_list->count() == 2);
  CHECK(find_layer_item(*layer_list, QStringLiteral("Folder")) != nullptr);          // kept, now a pixel layer
  CHECK(find_layer_item(*layer_list, QStringLiteral("Folder Paint A")) == nullptr);  // children flattened away
  CHECK(find_layer_item(*layer_list, QStringLiteral("Base")) != nullptr);

  QApplication::clipboard()->clear();
  require_action(window, "editSelectAllAction")->trigger();
  QApplication::processEvents();
  require_action(window, "editCopyAction")->trigger();
  QApplication::processEvents();
  // Copy yields the active layer -- the flattened folder -- which now holds both former children.
  const auto copied = QApplication::clipboard()->image().convertToFormat(QImage::Format_RGBA8888);
  CHECK(!copied.isNull());
  CHECK(copied.pixelColor(24, 8).alpha() > 0);   // folder child A
  CHECK(copied.pixelColor(38, 24).alpha() > 0);  // folder child B
}

void ui_merge_down_discards_hidden_layers() {
  patchy::Document document(48, 36, patchy::PixelFormat::rgba8());

  auto bottom_pixels = solid_pixels(48, 36, patchy::PixelFormat::rgba8(), Qt::transparent);
  fill_pixel_rect(bottom_pixels, QRect(2, 2, 10, 10), QColor(210, 40, 40, 255));
  document.add_layer(patchy::Layer(document.allocate_layer_id(), "Bottom", std::move(bottom_pixels)));

  auto middle_pixels = solid_pixels(48, 36, patchy::PixelFormat::rgba8(), Qt::transparent);
  fill_pixel_rect(middle_pixels, QRect(20, 4, 10, 10), QColor(40, 200, 40, 255));
  patchy::Layer middle(document.allocate_layer_id(), "Middle", std::move(middle_pixels));
  middle.set_visible(false);
  document.add_layer(std::move(middle));

  auto top_pixels = solid_pixels(48, 36, patchy::PixelFormat::rgba8(), Qt::transparent);
  fill_pixel_rect(top_pixels, QRect(34, 20, 10, 10), QColor(40, 40, 200, 255));
  document.add_layer(patchy::Layer(document.allocate_layer_id(), "Top", std::move(top_pixels)));

  patchy::ui::MainWindow window;
  window.add_document_session(std::move(document), QStringLiteral("Merge Hidden"));
  show_window(window);
  auto* layer_list = window.findChild<QListWidget*>(QStringLiteral("layerList"));
  CHECK(layer_list != nullptr);
  CHECK(layer_list->count() == 3);

  layer_list->clearSelection();
  for (int i = 0; i < layer_list->count(); ++i) {
    layer_list->item(i)->setSelected(true);
  }
  require_action(window, "layerMergeDownAction")->trigger();
  QApplication::processEvents();

  // The hidden middle layer is erased (not blocking the merge); the visible layers flatten into one.
  CHECK(layer_list->count() == 1);

  QApplication::clipboard()->clear();
  require_action(window, "editSelectAllAction")->trigger();
  QApplication::processEvents();
  require_action(window, "editCopyAction")->trigger();
  QApplication::processEvents();
  const auto copied = QApplication::clipboard()->image().convertToFormat(QImage::Format_RGBA8888);
  CHECK(!copied.isNull());
  CHECK(copied.pixelColor(6, 6).alpha() > 0);    // bottom rect kept
  CHECK(copied.pixelColor(38, 24).alpha() > 0);  // top rect kept
  CHECK(copied.pixelColor(24, 8).alpha() == 0);  // hidden middle rect erased
}

void ui_merge_down_flattens_entire_psd_to_single_layer() {
  const auto path = patchy::test::local_psd_fixture_path("ipad_main_v04.psd");
  if (!std::filesystem::exists(path)) {
    return;
  }
  auto document = patchy::psd::DocumentIo::read_file(path);

  patchy::ui::MainWindow window;
  show_window(window);
  window.add_document_session(std::move(document), QStringLiteral("iPad Flatten All"));
  auto* layer_list = window.findChild<QListWidget*>(QStringLiteral("layerList"));
  CHECK(layer_list != nullptr);
  CHECK(layer_list->count() > 1);

  // Select everything in the panel (folders and their contents) and merge -- this is the reported
  // scenario, including hidden layers that previously aborted the operation.
  layer_list->selectAll();
  QApplication::processEvents();
  require_action(window, "layerMergeDownAction")->trigger();
  QApplication::processEvents();

  // It all collapses to a single flat pixel layer with no folders left.
  auto& merged = patchy::ui::MainWindowTestAccess::document(window);
  CHECK(merged.layers().size() == 1);
  CHECK(merged.layers().front().kind() == patchy::LayerKind::Pixel);
  CHECK(merged.layers().front().children().empty());
  CHECK(layer_list->count() == 1);
}

