  CHECK(canvas->magnetic_lasso_width() == 25);
  CHECK(canvas->magnetic_lasso_edge_contrast() == 30);
  CHECK(canvas->magnetic_lasso_frequency() == 80);

  accept_new_document_dialog(320, 240);
